import java.util.ArrayList;

public ArrayList<ArrayList<Integer>> largestMatrix(int[][] grid) {
    int n = grid.length;
    ArrayList<ArrayList<Integer>> maxLocal = new ArrayList<>();

    for (int i = 1; i < n - 1; ++i) {
        maxLocal.add(new ArrayList<>());
        for (int j = 1; j < n - 1; ++j) {
            int max_val = grid[i - 1][j - 1];
            for (int x = -1; x <= 1; ++x) {
                for (int y = -1; y <= 1; ++y) {
                    max_val = Math.max(max_val, grid[i + x][j + y]);
                }
            }
            maxLocal.get(i - 1).add(max_val);
        }
    }

    return maxLocal;
}
